-- สร้างตาราง land_offices (normalized)
DROP TABLE IF EXISTS land_offices;
CREATE TABLE land_offices (
  id           BIGSERIAL PRIMARY KEY,
  office_name  TEXT,
  address      TEXT,
  sub_district TEXT,
  district     TEXT,
  province     TEXT,
  zip          TEXT
);
ALTER TABLE land_offices DISABLE ROW LEVEL SECURITY;
CREATE INDEX idx_land_offices_name ON land_offices(office_name);
CREATE INDEX idx_land_offices_province ON land_offices(province);

